import java.util.*;

public class Main {
    static void dfs(List<List<Integer>> adjList, int node, boolean[] visited, Deque<Integer> result) {
        visited[node] = true;
        for (int neighbor : adjList.get(node)) {
            if (!visited[neighbor]) {
                dfs(adjList, neighbor, visited, result);
            }
        }
        result.push(node); // add to front AFTER all dependents are processed
    }

    static List<Integer> topologicalSort(List<List<Integer>> adjList, int n) {
        boolean[] visited = new boolean[n];
        Deque<Integer> result = new ArrayDeque<>();

        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                dfs(adjList, i, visited, result);
            }
        }
        return new ArrayList<>(result);
    }

    public static void main(String[] args) {
        int n = 4;
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) adjList.add(new ArrayList<>());

        // 0 -> 1, 0 -> 2, 1 -> 3, 2 -> 3
        adjList.get(0).add(1);
        adjList.get(0).add(2);
        adjList.get(1).add(3);
        adjList.get(2).add(3);

        System.out.println(topologicalSort(adjList, n));
    }
}

import java.util.*;

public class Main {
    static List<Integer> topologicalSortKahn(List<List<Integer>> adjList, int n) {
        int[] inDegree = new int[n];
        for (List<Integer> neighbors : adjList) {
            for (int neighbor : neighbors) {
                inDegree[neighbor]++;
            }
        }

        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < n; i++) {
            if (inDegree[i] == 0) {
                queue.offer(i);
            }
        }

        List<Integer> result = new ArrayList<>();
        while (!queue.isEmpty()) {
            int current = queue.poll();
            result.add(current);

            for (int neighbor : adjList.get(current)) {
                inDegree[neighbor]--;
                if (inDegree[neighbor] == 0) {
                    queue.offer(neighbor);
                }
            }
        }
        return result;
    }

    public static void main(String[] args) {
        int n = 4;
        List<List<Integer>> adjList = new ArrayList<>();
        for (int i = 0; i < n; i++) adjList.add(new ArrayList<>());

        adjList.get(0).add(1);
        adjList.get(0).add(2);
        adjList.get(1).add(3);
        adjList.get(2).add(3);

        System.out.println(topologicalSortKahn(adjList, n));
    }
}

